import React, { useState, useEffect, useCallback } from 'react';
import { ReportData, ChannelData } from './types';
import { getInitialReportData, AVAILABLE_AGENTS } from './constants';
import { supabase } from './supabase';
import LeaderDashboard from './components/LeaderDashboard';
import ChannelEntry from './components/ChannelEntry';
import TerminalHub from './components/TerminalHub';
import { Shield, Monitor, LogOut, Signal, Zap, Globe, KeyRound, Database, WifiOff, LayoutGrid, Loader2, AlertCircle } from 'lucide-react';

type UserRole = 'leader' | 'hub';

const App: React.FC = () => {
  const [data, setData] = useState<ReportData>(getInitialReportData());
  const [dbAgents, setDbAgents] = useState<{mat: string, nome: string}[]>(AVAILABLE_AGENTS);
  const [currentRole, setCurrentRole] = useState<UserRole | null>(null);
  const [isLeaderAuthenticated, setIsLeaderAuthenticated] = useState(false);
  const [activeChannel, setActiveChannel] = useState<string | null>(null);
  const [activeShiftId, setActiveShiftId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [dbStatus, setDbStatus] = useState<'online' | 'offline' | 'checking'>('checking');

  // 1. Monitor de Sessão (Turno Ativo)
  const checkSession = useCallback(async () => {
    if (!supabase) return;
    try {
      const { data: shift } = await supabase
        .from('relatorios')
        .select('id, supervisor, turno, created_at, data_relatorio')
        .is('entregue_por', null)
        .order('created_at', { ascending: false })
        .limit(1)
        .maybeSingle();

      if (shift) {
        if (activeShiftId !== shift.id) {
          setActiveShiftId(shift.id);
          setData(prev => ({
            ...prev,
            shiftStarted: true,
            liderNome: shift.supervisor,
            turno: shift.turno,
            dataRelatorio: shift.data_relatorio,
            startTime: new Date(shift.created_at).toLocaleTimeString('pt-BR')
          }));
        }
      } else {
        setActiveShiftId(null);
        setData(prev => ({ ...prev, shiftStarted: false }));
      }
      setDbStatus('online');
    } catch (e) {
      setDbStatus('offline');
    }
  }, [activeShiftId]);

  // 2. Motor de Sincronização Unificado (Líder e Hub)
  const syncOperationData = useCallback(async () => {
    if (!activeShiftId || dbStatus !== 'online') return;

    try {
      const [agentsRes, inspectionsRes] = await Promise.all([
        supabase.from('relatorio_agentes').select('*').eq('relatorio_id', activeShiftId),
        supabase.from('relatorio_inspecoes').select('*').eq('relatorio_id', activeShiftId)
      ]);

      setData(prev => {
        const updatedCanais = { ...prev.canais };

        // Resetar listas para popular com dados do banco (Garante verdade única)
        const channels: (keyof ReportData['canais'])[] = ['bravo', 'alfa', 'charlie', 'fox'];
        channels.forEach(c => {
          // Se o canal não for o que está sendo editado localmente no Hub, atualizamos
          if (activeChannel !== c) {
             updatedCanais[c].agentes = [];
             updatedCanais[c].inspecoes = [];
             updatedCanais[c].status = 'Pendente';
          }
        });

        // Mapear Agentes
        if (agentsRes.data) {
          agentsRes.data.forEach((a: any) => {
            const canal = a.canal as keyof ReportData['canais'];
            if (updatedCanais[canal] && activeChannel !== canal) {
              updatedCanais[canal].agentes.push({ id: a.id, mat: a.mat, nome: a.nome, horario: a.horario });
              updatedCanais[canal].status = 'Finalizado';
            }
          });
        }

        // Mapear Inspeções
        if (inspectionsRes.data) {
          inspectionsRes.data.forEach((i: any) => {
            const canal = i.canal as keyof ReportData['canais'];
            if (updatedCanais[canal] && activeChannel !== canal) {
              updatedCanais[canal].inspecoes.push({ 
                id: i.id, 
                descricao: i.descricao, 
                horario: i.horario, 
                status: i.status as 'OK' | 'Pendente' | 'N/A' 
              });
              updatedCanais[canal].status = 'Finalizado';
            }
          });
        }

        return { ...prev, canais: updatedCanais };
      });
    } catch (err) {
      console.error("Sync error:", err);
    }
  }, [activeShiftId, dbStatus, activeChannel]);

  useEffect(() => {
    checkSession();
    const sessionInterval = setInterval(checkSession, 5000);
    const dataInterval = setInterval(syncOperationData, 3000); // Sync mais rápido para tempo real

    // Busca agentes apenas uma vez no início
    supabase?.from('agentes').select('mat, nome').order('nome').then(({ data }) => {
      if (data) setDbAgents(data);
    });

    return () => {
      clearInterval(sessionInterval);
      clearInterval(dataInterval);
    };
  }, [checkSession, syncOperationData]);

  const handleStartShift = async (lider: {mat: string, nome: string}, turno: string) => {
    setIsSyncing(true);
    try {
      await supabase.from('relatorios').update({ entregue_por: 'ENCERRADO' }).is('entregue_por', null);

      const { data: newShift } = await supabase.from('relatorios').insert([{
        turno, 
        supervisor: lider.nome, 
        data_relatorio: new Date().toISOString().split('T')[0], 
        recebimento_de: 'INÍCIO DE TURNO'
      }]).select().single();

      if (newShift) {
        setActiveShiftId(newShift.id);
        setData(prev => ({
          ...prev,
          shiftStarted: true,
          liderNome: lider.nome,
          liderMat: lider.mat,
          turno: turno,
          startTime: new Date().toLocaleTimeString('pt-BR')
        }));
      }
    } catch (e) {
      alert("Erro ao conectar ao banco de dados.");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleChannelUpdate = (canal: string, newData: ChannelData) => {
    setData(prev => ({
      ...prev,
      canais: { ...prev.canais, [canal]: newData }
    }));
  };

  if (!currentRole) {
    return (
      <div className="h-screen bg-[#05060a] flex flex-col items-center justify-center p-6">
        <div className="max-w-4xl w-full text-center space-y-12">
          <div className="flex flex-col items-center space-y-4">
            <div className="bg-blue-600 p-5 rounded-2xl shadow-[0_0_50px_rgba(37,99,235,0.4)]">
              <Shield className="w-16 h-16 text-white" />
            </div>
            <h1 className="text-4xl font-black text-white uppercase tracking-[0.4em]">SISTEMA AVSEC</h1>
            <p className="text-blue-500 font-black uppercase tracking-[0.2em] text-xs leading-none">WFS Integrated Operations</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-3xl mx-auto">
            <RoleCard icon={<Monitor className="w-10 h-10" />} title="Portal Líder" subtitle="Gestão Tática HQ" onClick={() => setCurrentRole('leader')} />
            <RoleCard icon={<Globe className="w-10 h-10" />} title="Terminal Hub" subtitle="Postos de Inspeção" onClick={() => setCurrentRole('hub')} />
          </div>
          <div className="flex items-center justify-center gap-6 pt-10 border-t border-slate-900">
             <div className="flex items-center gap-2">
                <Database className={`w-3.5 h-3.5 ${dbStatus === 'online' ? 'text-emerald-500' : 'text-amber-500'}`} />
                <span className={`text-[9px] font-black uppercase tracking-widest ${dbStatus === 'online' ? 'text-emerald-500' : 'text-amber-500'}`}>
                   {dbStatus === 'online' ? 'SISTEMA ONLINE' : 'ERRO DE CONEXÃO'}
                </span>
             </div>
          </div>
        </div>
      </div>
    );
  }

  if (currentRole === 'leader' && !isLeaderAuthenticated) {
    return <LeaderLogin onSuccess={() => setIsLeaderAuthenticated(true)} onBack={() => setCurrentRole(null)} />;
  }

  if (currentRole === 'leader' && !data.shiftStarted) {
    return <StartShiftScreen agents={dbAgents} onStart={handleStartShift} onBack={() => { setIsLeaderAuthenticated(false); setCurrentRole(null); }} isSyncing={isSyncing} />;
  }

  if (currentRole === 'hub' && !data.shiftStarted) {
    return (
      <div className="h-screen bg-[#05060a] flex items-center justify-center p-6 text-center">
        <div className="space-y-6">
          <div className="bg-amber-500/10 p-6 rounded-full w-fit mx-auto border border-amber-500/20">
            <WifiOff className="w-12 h-12 text-amber-500 animate-pulse" />
          </div>
          <h2 className="text-2xl font-black text-white uppercase tracking-widest">Aguardando Liberação</h2>
          <p className="text-slate-500 text-sm max-w-md mx-auto">O Supervisor HQ ainda não iniciou o turno operacional.</p>
          <button onClick={() => setCurrentRole(null)} className="text-blue-500 font-black text-[10px] uppercase tracking-widest py-4">Voltar</button>
        </div>
      </div>
    );
  }

  if (activeChannel) {
    return (
      <div className="h-screen flex flex-col bg-[#0f1117]">
        <header className="h-14 bg-[#1a1c26] border-b border-slate-700 flex items-center justify-between px-6 shrink-0 z-50">
          <button onClick={() => setActiveChannel(null)} className="p-2 hover:bg-white/5 rounded-lg text-slate-400 flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors">
            <LayoutGrid className="w-4 h-4" /> Voltar ao Hub
          </button>
          <div className="flex items-center gap-4 text-emerald-500 bg-emerald-500/10 px-4 py-1.5 rounded-full border border-emerald-500/20">
             <Zap className="w-3.5 h-3.5" />
             <span className="text-[10px] font-black uppercase">Posto Ativo: {activeChannel.toUpperCase()}</span>
          </div>
        </header>
        <main className="flex-grow overflow-hidden">
           <ChannelEntry 
             agents={dbAgents} 
             canal={activeChannel} 
             data={data.canais[activeChannel as keyof ReportData['canais']]} 
             activeShiftId={activeShiftId} 
             onUpdate={(newData) => handleChannelUpdate(activeChannel, newData)} 
           />
        </main>
      </div>
    );
  }

  return (
    <div className="h-screen flex flex-col bg-[#0f1117] text-slate-200 overflow-hidden">
      <header className="h-16 bg-[#1a1c26] border-b border-slate-700 flex items-center justify-between px-8 shrink-0 z-50 shadow-2xl">
        <div className="flex items-center gap-5">
          <div className="bg-blue-600 p-2 rounded shadow-lg shadow-blue-900/40"><Shield className="w-5 h-5 text-white" /></div>
          <div>
            <h1 className="text-xs font-black uppercase tracking-[0.2em] text-white leading-none">{currentRole === 'leader' ? 'COMANDO HQ' : 'TERMINAL HUB'}</h1>
            <p className="text-[9px] text-blue-500 uppercase font-black tracking-[0.3em] mt-2">Eduardo Gomes - SBEG</p>
          </div>
        </div>
        <div className="flex items-center gap-8">
          <div className="text-right border-l border-slate-700 pl-8">
            <p className="text-xs font-black text-white uppercase leading-none">{data.liderNome || 'SUPERVISOR'}</p>
            <div className="flex items-center justify-end gap-2 mt-2">
               <Signal className={`w-3.5 h-3.5 text-emerald-500 ${dbStatus === 'online' ? 'animate-pulse' : ''}`} />
               <p className="text-[9px] font-mono font-bold uppercase text-emerald-500">{dbStatus === 'online' ? 'Sincronizado' : 'Offline'}</p>
            </div>
          </div>
          <button onClick={() => { window.location.reload(); }} className="flex items-center gap-3 bg-red-900/10 hover:bg-red-600 border border-red-500/30 text-red-500 hover:text-white px-5 py-2 transition-all rounded">
            <LogOut className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Sair</span>
          </button>
        </div>
      </header>
      <main className="flex-grow overflow-hidden relative">
        {currentRole === 'leader' ? <LeaderDashboard data={data} activeShiftId={activeShiftId} /> : <TerminalHub data={data} onSelectChannel={(id) => setActiveChannel(id)} />}
      </main>
    </div>
  );
};

const RoleCard = ({ icon, title, subtitle, onClick }: any) => (
  <button onClick={onClick} className="bg-[#11131a] border border-blue-500/20 p-10 flex flex-col items-center gap-6 transition-all hover:translate-y-[-5px] hover:border-blue-500/50 active:scale-95 group rounded-lg shadow-2xl">
    <div className="p-6 bg-black/40 rounded-full text-blue-500 group-hover:scale-110 transition-transform">{icon}</div>
    <div className="text-center space-y-2">
      <h3 className="text-xl font-black uppercase tracking-[0.2em] text-white">{title}</h3>
      <p className="text-[9px] font-black text-slate-500 uppercase tracking-[0.1em] group-hover:text-slate-300 transition-colors">{subtitle}</p>
    </div>
  </button>
);

const LeaderLogin = ({ onSuccess, onBack }: { onSuccess: () => void, onBack: () => void }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const handleSubmit = (e: React.FormEvent) => { e.preventDefault(); if (password === 'admin') onSuccess(); else { setError(true); setTimeout(() => setError(false), 2000); } };
  return (
    <div className="h-screen bg-[#05060a] flex items-center justify-center p-6">
      <div className="bg-[#11131a] border border-blue-500/20 max-w-sm w-full p-10 shadow-2xl space-y-8 rounded-xl">
        <div className="p-4 bg-blue-600/10 w-fit mx-auto rounded-full"><KeyRound className="w-8 h-8 text-blue-500" /></div>
        <h2 className="text-xl font-black text-white uppercase tracking-widest text-center">Acesso HQ</h2>
        <form onSubmit={handleSubmit} className="space-y-6">
          <input autoFocus type="password" value={password} onChange={(e) => setPassword(e.target.value)} placeholder="SENHA" className={`w-full bg-black border ${error ? 'border-red-500' : 'border-slate-800'} p-4 text-center text-xs font-black text-white tracking-[0.5em] outline-none rounded-lg focus:border-blue-500`} />
          <button type="submit" className="w-full bg-blue-600 hover:bg-blue-500 text-white p-4 font-black text-[11px] uppercase tracking-[0.3em] rounded-lg">Confirmar</button>
          <button type="button" onClick={onBack} className="w-full text-[9px] font-bold text-slate-600 uppercase">Voltar</button>
        </form>
      </div>
    </div>
  );
};

const StartShiftScreen = ({ agents, onStart, onBack, isSyncing }: any) => {
  const [selectedAgent, setSelectedAgent] = useState('');
  const [selectedShift, setSelectedShift] = useState('A');
  const handleSubmit = (e: React.FormEvent) => { e.preventDefault(); const agent = agents.find((a:any) => a.mat === selectedAgent); if (agent) onStart(agent, selectedShift); };
  return (
    <div className="h-screen bg-[#05060a] flex items-center justify-center p-6">
      <div className="bg-[#11131a] border border-blue-500/20 max-w-xl w-full p-12 shadow-2xl space-y-10 rounded-2xl text-center">
        <h2 className="text-2xl font-black text-white uppercase tracking-widest">Novo Turno Operacional</h2>
        <form onSubmit={handleSubmit} className="space-y-8 text-left">
          <select required value={selectedAgent} onChange={(e) => setSelectedAgent(e.target.value)} className="w-full bg-black border border-slate-800 p-5 text-sm font-bold text-slate-200 outline-none rounded-xl focus:border-blue-500">
            <option value="">Supervisor Responsável...</option>
            {agents.map((a:any) => <option key={a.mat} value={a.mat}>{a.nome} ({a.mat})</option>)}
          </select>
          <div className="grid grid-cols-4 gap-4">
            {['A', 'B', 'C', 'D'].map(l => (
              <button key={l} type="button" onClick={() => setSelectedShift(l)} className={`py-5 border text-sm font-black rounded-xl ${selectedShift === l ? 'bg-blue-600 border-blue-400 text-white' : 'bg-black border-slate-800 text-slate-600'}`}>{l}</button>
            ))}
          </div>
          <button disabled={isSyncing} type="submit" className="w-full bg-emerald-600 hover:bg-emerald-500 text-white p-5 font-black text-xs uppercase tracking-[0.2em] rounded-xl flex items-center justify-center gap-3 transition-all active:scale-95">
            {isSyncing ? <Loader2 className="w-5 h-5 animate-spin" /> : <Zap className="w-5 h-5" />}
            {isSyncing ? 'INICIANDO...' : 'LIBERAR REDE OPERACIONAL'}
          </button>
          <button type="button" onClick={onBack} className="w-full text-[9px] font-black text-slate-600 uppercase tracking-widest text-center">Voltar</button>
        </form>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ChannelData, Agent, ChannelInspection } from '../types';
import { SHIFTS } from '../constants';
import { supabase } from '../supabase';
import { Plus, Trash2, Send, ShieldAlert, Clock, Loader2, Info, ClipboardCheck, UserPlus, Database, CheckCircle2 } from 'lucide-react';

interface Props {
  canal: string;
  data: ChannelData;
  agents: {mat: string, nome: string}[];
  activeShiftId: string | null;
  onUpdate: (data: ChannelData) => void;
}

const ChannelEntry: React.FC<Props> = ({ canal, data, agents, activeShiftId, onUpdate }) => {
  const [lastSync, setLastSync] = useState<string | null>(null);
  const [isTransmitting, setIsTransmitting] = useState(false);
  const [autoSaveTimer, setAutoSaveTimer] = useState<NodeJS.Timeout | null>(null);

  // Auto-save opcional: Toda vez que mudar localmente, marcamos como "Preenchendo"
  const markAsPreenchendo = () => {
    if (data.status !== 'Preenchendo') {
      onUpdate({ ...data, status: 'Preenchendo' });
    }
  };

  const addAgent = () => {
    const newAgent: Agent = { id: crypto.randomUUID(), mat: '', nome: '', horario: SHIFTS[0].value };
    onUpdate({ ...data, agentes: [...data.agentes, newAgent], status: 'Preenchendo' });
  };

  const updateAgent = (id: string, updates: Partial<Agent>) => {
    onUpdate({
      ...data,
      agentes: data.agentes.map(a => a.id === id ? { ...a, ...updates } : a),
      status: 'Preenchendo'
    });
  };

  const addInspection = () => {
    const now = new Date();
    const currentTime = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;
    const newInsp: ChannelInspection = { 
      id: crypto.randomUUID(), 
      descricao: 'Varredura padrão AVSEC realizada sem anormalidades', 
      horario: currentTime, 
      status: 'OK' 
    };
    onUpdate({ ...data, inspecoes: [...data.inspecoes, newInsp], status: 'Preenchendo' });
  };

  const handleTransmit = async () => {
    if (!activeShiftId) {
      alert("ERRO: Rede HQ não detectada. Aguarde o Supervisor iniciar o turno.");
      return;
    }

    setIsTransmitting(true);
    const syncTime = new Date().toLocaleTimeString('pt-BR');

    try {
      // 1. Limpar registros anteriores deste canal para evitar duplicidade
      await Promise.all([
        supabase.from('relatorio_agentes').delete().eq('relatorio_id', activeShiftId).eq('canal', canal),
        supabase.from('relatorio_inspecoes').delete().eq('relatorio_id', activeShiftId).eq('canal', canal)
      ]);

      // 2. Inserir novos registros de Agentes
      if (data.agentes.length > 0) {
        const agentsToInsert = data.agentes
          .filter(a => a.nome !== '')
          .map(a => ({
            relatorio_id: activeShiftId, 
            canal: canal, 
            mat: a.mat, 
            nome: a.nome, 
            horario: a.horario
          }));
        if (agentsToInsert.length > 0) {
          await supabase.from('relatorio_agentes').insert(agentsToInsert);
        }
      }

      // 3. Inserir registros de Inspeção
      if (data.inspecoes.length > 0) {
        const inspectionsToInsert = data.inspecoes.map(i => ({
          relatorio_id: activeShiftId, 
          canal: canal, 
          descricao: i.descricao, 
          horario: i.horario, 
          status: i.status
        }));
        await supabase.from('relatorio_inspecoes').insert(inspectionsToInsert);
      }

      // 4. Notificar Sucesso
      onUpdate({ ...data, status: 'Finalizado' });
      setLastSync(syncTime);
    } catch (err) {
      console.error("Transmit error:", err);
      alert("Falha na transmissão dos dados.");
    } finally {
      setIsTransmitting(false);
    }
  };

  return (
    <div className="h-full overflow-y-auto p-8 space-y-8 bg-[#0f1117] pb-24 text-slate-200 animate-in fade-in duration-500">
      <div className="flex items-center justify-between border-b border-slate-700 pb-6">
        <div>
          <h2 className="text-2xl font-black text-white uppercase tracking-tight flex items-center gap-4">
            <span className="bg-blue-600 w-2 h-8 rounded-full"></span>
            POSTO DE INSPEÇÃO: {canal.toUpperCase()}
          </h2>
          <div className="flex items-center gap-3 mt-2">
             <div className="flex items-center gap-1.5 text-[10px] font-black text-emerald-500 uppercase tracking-widest bg-emerald-500/10 px-2 py-0.5 rounded border border-emerald-500/20">
                <Database className="w-3 h-3" /> Conexão Segura HQ
             </div>
             <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
               {lastSync ? `SINCRONIZADO ÀS: ${lastSync}` : 'AGUARDANDO PRIMEIRA TRANSMISSÃO'}
             </p>
          </div>
        </div>
        <button 
          onClick={handleTransmit}
          disabled={isTransmitting}
          className={`px-10 py-4 font-black text-[12px] uppercase tracking-[0.2em] transition-all flex items-center gap-3 active:scale-95 ${isTransmitting ? 'bg-slate-700' : 'bg-blue-600 hover:bg-blue-500 shadow-xl shadow-blue-900/20'} text-white rounded-lg`}
        >
          {isTransmitting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
          {isTransmitting ? 'SINCRONIZANDO...' : 'TRANSMITIR DADOS HQ'}
        </button>
      </div>

      <div className="grid grid-cols-12 gap-10">
        <div className="col-span-12 lg:col-span-7 space-y-8">
          <section className="bg-[#1a1c26] border border-slate-700 shadow-2xl rounded-xl overflow-hidden">
            <div className="bg-slate-700/20 p-5 flex justify-between items-center border-b border-slate-700">
               <div className="flex items-center gap-3 text-slate-300">
                  <ShieldAlert className="w-5 h-5 text-amber-500" />
                  <h3 className="text-[11px] font-black uppercase tracking-widest">Logs de Varredura</h3>
               </div>
               <button onClick={addInspection} className="text-[10px] font-black uppercase bg-amber-600 hover:bg-amber-500 text-white px-5 py-2 rounded-lg transition-colors">Nova Varredura</button>
            </div>
            <div className="p-6 space-y-4">
              {data.inspecoes.map((insp) => (
                <div key={insp.id} className="flex items-center gap-4 bg-black/40 p-4 border border-slate-700/50 rounded-lg group hover:border-slate-500 transition-colors">
                  <Clock className="w-4 h-4 text-slate-600" />
                  <input type="time" value={insp.horario} onChange={(e) => onUpdate({...data, status: 'Preenchendo', inspecoes: data.inspecoes.map(i => i.id === insp.id ? {...i, horario: e.target.value} : i)})} className="bg-transparent border-b border-slate-800 text-emerald-400 font-mono text-sm outline-none focus:border-emerald-500" />
                  <input value={insp.descricao} onChange={(e) => onUpdate({...data, status: 'Preenchendo', inspecoes: data.inspecoes.map(i => i.id === insp.id ? {...i, descricao: e.target.value} : i)})} className="flex-grow bg-transparent border-b border-slate-800 text-sm py-1 outline-none text-slate-300 focus:border-blue-500" />
